sql:
SELECT brand_name
FROM brands
WHERE founded_year = (SELECT MIN(founded_year) FROM brands);

external_knowledge:
"best-selling" refers to the product with the highest total quantity sold in each region; 
"compliant products" refers to products with a compliance status of 'Compliant' as per the regulatory agency; 
"most active users" refers to the users with the highest number of orders for each product.

- 'cash cows' refers to the top products with the highest revenue; 
- 'farm of compliant products' means products with a compliance status of 'Compliant'; 
- 'received a stamp of approval from verified customers' means having verified purchase reviews.

sql:
SELECT DISTINCT AVG(revenue / quantity_sold) AS average_order_value
FROM sales_data
GROUP BY product_id, region, channel;
